# Policy initiative: group multiple GC and extension policies into a single assignment
# For Arc governance, bundle: AMA deploy, DCR association, Defender DINE, GC audit

# Create a custom initiative (policy set definition) combining 4 policies
cat << 'EOF' > arc_governance_initiative.json
{
  "properties": {
    "displayName": "Arc Server Governance Baseline",
    "description": "Deploys AMA, DCR association, Defender for Servers, and audits Windows Security Baseline",
    "policyDefinitions": [
      {
        "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/b0cdcf83-5f9a-4e26-8e7f-2a8e47f12a10",
        "policyDefinitionReferenceId": "DeployAMALinux",
        "parameters": {
          "logAnalyticsWorkspaceId": {"value": "[parameters('workspaceId')]"}
        }
      },
      {
        "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/2ea82cdd-f2e8-4500-af75-67a2e084ca74",
        "policyDefinitionReferenceId": "AssociateDCRLinux",
        "parameters": {
          "dcrResourceId": {"value": "[parameters('dcrId')]"}
        }
      },
      {
        "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/2227c820-e27a-4c05-9a0e-4b9d9d6d5f9c",
        "policyDefinitionReferenceId": "EnableDefenderSQL",
        "parameters": {}
      },
      {
        "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/72650e9f-97bc-4b2a-ab5f-9781a9fcecbc",
        "policyDefinitionReferenceId": "AuditWindowsSecurityBaseline",
        "parameters": {}
      }
    ],
    "parameters": {
      "workspaceId": {"type": "String", "metadata": {"displayName": "Log Analytics Workspace ID"}},
      "dcrId": {"type": "String", "metadata": {"displayName": "Data Collection Rule Resource ID"}}
    }
  }
}
EOF

# Create the initiative at subscription scope
az policy set-definition create \
  --name 'arc-governance-baseline' \
  --definitions arc_governance_initiative.json \
  --subscription '<sub>'

# Assign the initiative (one assignment covers all 4 policies)
az policy assignment create \
  --name 'arc-baseline-assign' \
  --display-name 'Arc Server Governance Baseline' \
  --policy-set-definition 'arc-governance-baseline' \
  --params '{
    "workspaceId":{"value":"/subscriptions/<sub>/resourceGroups/<rg>/providers/Microsoft.OperationalInsights/workspaces/<ws>"},
    "dcrId":{"value":"/subscriptions/<sub>/resourceGroups/<rg>/providers/Microsoft.Insights/dataCollectionRules/<dcr>"}
  }' \
  --scope '/subscriptions/<sub>' \
  --mi-system-assigned \
  --location eastus

# Grant the initiative MSI all required roles (one per DINE policy in the set)
INIT_MSI=$(az policy assignment show \
  --name 'arc-baseline-assign' \
  --scope '/subscriptions/<sub>' \
  --query 'identity.principalId' -o tsv)

for role in Contributor 'Guest Configuration Resource Contributor' 'Log Analytics Contributor'; do
  az role assignment create \
    --role "$role" \
    --assignee-object-id "$INIT_MSI" \
    --assignee-principal-type ServicePrincipal \
    --scope '/subscriptions/<sub>'
done

# Create remediation tasks for all DINE policies in the initiative
for policy_ref in DeployAMALinux AssociateDCRLinux EnableDefenderSQL; do
  az policy remediation create \
    --name "arc-baseline-${policy_ref}-remediation" \
    --policy-assignment 'arc-baseline-assign' \
    --definition-reference-id "$policy_ref" \
    --resource-discovery-mode ExistingNonCompliant
done
